CREATE TABLE IF NOT EXISTS valorapesquisa.audit_logs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid NULL, user_id uuid NULL, level text NOT NULL DEFAULT 'info', category text NOT NULL DEFAULT 'application', action text NOT NULL, entity_type text, entity_id text, message text, metadata_json jsonb NOT NULL DEFAULT '{}'::jsonb, ip_address text, user_agent text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), created_by uuid, updated_by uuid, is_deleted boolean NOT NULL DEFAULT false);
